import sys

def solve(data: str) -> str:
    rows = [line.split(',', 1) for line in data.splitlines() if line.strip()]
    seen: set[str] = set(); duplicates = 0; missing = 0
    for identifier, label in rows:
        if identifier in seen:
            duplicates += 1
        seen.add(identifier)
        if not label.strip():
            missing += 1
    return f"rows={len(rows)} duplicates={duplicates} missing={missing}"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
